body:
**Verilator version**: Verilator 5.018 2023-10-30 rev UNKNOWN.REV
**OS**: MAC

I wrote a simple combinatoral logic in verilog as follows:

```
module dummy (
    input clk,
    input [7:0] vector1 [3:0],
    output reg [7:0] vector2 [3:0]
);

always @* begin
    for (integer i = 0; i < 4; i = i + 1) begin
        vector2[i] = vector1[i];
    end  
end

endmodule

```

And the following testbench:

```
module tb0;
    // Inputs
    reg clk;
    reg [7:0] data_in1 [3:0];

    // Output
    wire [7:0] result [3:0];

    // Instantiate the module under test
    dummy uut (
        .clk(clk),
        .vector1(data_in1),
        .vector2(result)
    );

    // Clock generation
    always begin
        #5 clk = ~clk; // Toggle clock every 5 ns
    end

    initial begin
        $monitor("Time = %d: data_in1[1] = %d, data_out[1] = %d", $time, data_in1[1], result[1]); 
        
        clk = 0;
        data_in1[0] = 8'h00;
        data_in1[1] = 8'h00;
        data_in1[2] = 8'h00;
        data_in1[3] = 8'h00;

        #11 data_in1[0] = 8'h0f;
        #11 data_in1[1] = 8'h04;
        #11 data_in1[2] = 8'h0e;
        #11 data_in1[3] = 8'h0a;
        
        #20 $finish;
    end
endmodule

```

When I compile and run with: 

```
verilator --binary tb0.v dummy.v -top-module tb0
./obj_dir/Vtb0
```

I get the following output:

```
Time =                    0: data_in1[1] =   0, data_out[1] =   0
Time =                    5: data_in1[1] =   0, data_out[1] =   0
Time =                    5: data_in1[1] =   0, data_out[1] =   0
Time =                   10: data_in1[1] =   0, data_out[1] =   0
Time =                   10: data_in1[1] =   0, data_out[1] =   0
Time =                   11: data_in1[1] =   0, data_out[1] =   0
Time =                   11: data_in1[1] =   0, data_out[1] =   0
Time =                   15: data_in1[1] =   0, data_out[1] =   0
Time =                   15: data_in1[1] =   0, data_out[1] =   0
Time =                   20: data_in1[1] =   0, data_out[1] =   0
Time =                   20: data_in1[1] =   0, data_out[1] =   0
Time =                   22: data_in1[1] =   4, data_out[1] =   0
Time =                   22: data_in1[1] =   4, data_out[1] =   0
Time =                   25: data_in1[1] =   4, data_out[1] =   0
Time =                   25: data_in1[1] =   4, data_out[1] =   0
....

```

But `data_out[1]` should change to 4 at `time=20`. I tried the exactly the same code on other platforms (e.g., edaplayground), and was able to get `data_out[1]=4`. I wonder what am I missing? Or if this is a Verilator bug.
